import pytest

from chat.llm import stream_chat_tokens


@pytest.mark.asyncio
async def test_stream_chat_tokens_yields(monkeypatch: pytest.MonkeyPatch) -> None:
    class FakeChunk:
        def __init__(self, content: str) -> None:
            self.content = content

    class FakeLLM:
        async def astream(self, messages):
            for c in ["Hello", " there"]:
                yield FakeChunk(c)

    monkeypatch.setattr("chat.llm._get_llm", lambda: FakeLLM())

    tokens = []
    async for token in stream_chat_tokens("hi"):
        tokens.append(token)
    assert tokens == ["Hello", " there"]


@pytest.mark.asyncio
async def test_stream_chat_tokens_skips_empty(monkeypatch: pytest.MonkeyPatch) -> None:
    class FakeChunk:
        def __init__(self, content: str | None) -> None:
            self.content = content

    class FakeLLM:
        async def astream(self, messages):
            for c in ["Hi", None, "!"]:
                yield FakeChunk(c)

    monkeypatch.setattr("chat.llm._get_llm", lambda: FakeLLM())

    tokens = []
    async for token in stream_chat_tokens("hi"):
        tokens.append(token)
    assert tokens == ["Hi", "!"]

