<script>
(function () {
    const input = document.getElementById('chat-input');
    const form = document.getElementById('chat-form');
    const messagesDiv = document.getElementById('messages');
    const welcome = document.getElementById('welcome');
    let ws = null;
    let currentAssistantEl = null;

    function getWSUrl() {
        const loc = window.location;
        const proto = loc.protocol === 'https:' ? 'wss:' : 'ws:';
        return proto + '//' + loc.host + '/ws/chat/';
    }

    function connect() {
        ws = new WebSocket(getWSUrl());
        ws.onopen = function () { console.log('WS connected'); };
        ws.onclose = function () {
            console.log('WS closed, reconnecting in 1s');
            setTimeout(connect, 1000);
        };
        ws.onerror = function () { ws.close(); };
    }

    function appendUserMessage(text) {
        if (welcome) welcome.remove();
        const el = document.createElement('div');
        el.className = 'flex justify-end';
        el.innerHTML = '<div class="rounded-lg bg-blue-600 px-4 py-2 max-w-[75%] text-sm">' + escapeHtml(text) + '</div>';
        messagesDiv.appendChild(el);
    }

    function appendAssistantMessage() {
        if (welcome) welcome.remove();
        currentAssistantEl = document.createElement('div');
        currentAssistantEl.className = 'flex justify-start';
        currentAssistantEl.innerHTML = '<div class="rounded-lg bg-gray-800 px-4 py-2 max-w-[75%] text-sm whitespace-pre-wrap"></div>';
        messagesDiv.appendChild(currentAssistantEl);
    }

    function escapeHtml(str) {
        const d = document.createElement('div');
        d.textContent = str;
        return d.innerHTML;
    }

    function scrollToBottom() {
        const area = document.getElementById('chat-area');
        area.scrollTop = area.scrollHeight;
    }

    function handleWSMessage(event) {
        const data = JSON.parse(event.data);
        if (data.type === 'start') {
            appendAssistantMessage();
        } else if (data.type === 'token' && currentAssistantEl) {
            const inner = currentAssistantEl.querySelector('div');
            inner.textContent += data.content;
            scrollToBottom();
        } else if (data.type === 'end') {
            currentAssistantEl = null;
            scrollToBottom();
        } else if (data.type === 'error') {
            alert('Error: ' + data.content);
        }
    }

    function sendMessage(text) {
        if (!ws || ws.readyState !== WebSocket.OPEN) {
            alert('Not connected. Please wait…');
            return;
        }
        ws.send(JSON.stringify({ message: text }));
    }

    form.addEventListener('submit', function (e) {
        e.preventDefault();
        const text = input.value.trim();
        if (!text) return;
        appendUserMessage(text);
        sendMessage(text);
        input.value = '';
    });

    connect();

    // Override ws onmessage after initial setup
    const origOnMessage = ws.onmessage;
    ws.onmessage = function (event) {
        handleWSMessage(event);
    };
    // Also patch future reconnections
    const origConnect = connect;
    connect = function () {
        origConnect();
        ws.onmessage = function (event) {
            handleWSMessage(event);
        };
    };
})();
